#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        long long a = 1, b = 1, c;
        if (n == 0 || n == 1) {
            printf("1\n");
            continue;
        }
        for (int i = 2; i <= n; ++i) {
            c = a + b;
            a = b;
            b = c;
        }
        printf("%lld\n", b);
    }
    return 0;
}

